import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c,e as s}from"./app-be253e4c.js";const n={},o=s(`<h1 id="cmp命令" tabindex="-1"><a class="header-anchor" href="#cmp命令" aria-hidden="true">#</a> cmp命令</h1><p><code>cmp</code>命令用来比较两个文件是否有差异，当相互比较的两个文件完全一样时，则该指令不会输出任何信息，若发现有差异，预设会标示出第一个不同之处的字符和列数编号，若不指定任何文件名称或是所给予的文件名为<code>-</code>，则<code>cmp</code>指令会从标准输入设备读取数据。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">cmp</span> <span class="token punctuation">[</span>-clsv<span class="token punctuation">]</span><span class="token punctuation">[</span>-i <span class="token operator">&lt;</span>number of characters<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>--help<span class="token punctuation">]</span><span class="token punctuation">[</span>file<span class="token punctuation">]</span><span class="token punctuation">[</span>file<span class="token punctuation">]</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-c</code>或<code>--print-chars</code>: 除了标明差异处的十进制字码之外，一并显示该字符所对应字符。</li><li><code>-i &lt;number of characters&gt;</code>或<code>--ignore-initial=&lt;number of characters&gt;</code>: 指定跳过的数目。</li><li><code>-l</code>或<code>--verbose</code>: 标示出所有不一样的地方。</li><li><code>-s</code>或<code>--quiet</code>或<code>--silent</code>: 不显示错误信息。</li><li><code>-v</code>或<code>--version</code>: 显示版本信息。</li><li><code>--help</code>: 在线帮助。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>比较<code>file.txt</code>与<code>file2.txt</code>文件的差异，如果文件相同，则不显示消息，如果文件不同，则显示第一个不同的位置。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">cmp</span> file.txt file2.txt
</code></pre></div><p>比较<code>file.txt</code>与<code>file2.txt</code>文件的差异，标出所有不同之处。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">cmp</span> <span class="token parameter variable">-l</span> file.txt file2.txt
</code></pre></div><p>比较<code>file.txt</code>与自定义输入内容的差异，输入内容后按<code>Ctrl+D</code>输出<code>EOF</code>标识后结束输入。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">cmp</span> file.txt -
</code></pre></div>`,13),t=[o];function d(l,i){return a(),c("div",null,t)}const h=e(n,[["render",d],["__file","cmp.html.vue"]]);export{h as default};
